// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract OpenInnovationTrack is ERC721, ERC721Enumerable, ReentrancyGuard, Ownable {
    uint256 private _nextTokenId;
    mapping(uint256 => bool) private _isSold;

    constructor() ERC721("OpenInnovationTrack", "OIT") {}

    function mint(address to) external onlyOwner nonReentrant {
        require(!_isSold[_nextTokenId], "Item already sold");
        _safeMint(to, _nextTokenId);
        _isSold[_nextTokenId] = true;
        _nextTokenId++;
    }

    function _beforeTokenTransfer(address from, address to, uint256 tokenId) internal override(ERC721, ERC721Enumerable) {
        require(!_isSold[tokenId], "Item already sold");
        super._beforeTokenTransfer(from, to, tokenId);
    }

    function supportsInterface(bytes4 interfaceId) public view override(ERC721, ERC721Enumerable) returns (bool) {
        return super.supportsInterface(interfaceId);
    }
}
