// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "../OpenInnovationTrack.sol";

contract OpenInnovationTrackTest is Test {
    OpenInnovationTrack public oit;

    function setUp() public {
        oit = new OpenInnovationTrack();
    }

    function testMint() public {
        oit.mint(address(this));
        assertEq(oit.ownerOf(0), address(this));
        assertTrue(oit._isSold[0]);
    }

    function testReentrancy() public {
        address attacker = address(new ReentrancyAttacker(address(oit)));
        vm.expectRevert();
        vm.prank(attacker);
        oit.mint(attacker);
    }

    function testCannotMintSoldItem() public {
        oit.mint(address(this));
        vm.expectRevert("Item already sold");
        oit.mint(address(this));
    }
}

contract ReentrancyAttacker {
    OpenInnovationTrack public oit;

    constructor(address _oit) {
        oit = OpenInnovationTrack(_oit);
    }

    function attack() external {
        oit.mint(address(this));
    }

    function onERC721Received(address, address, uint256, bytes memory) external returns (bytes4) {
        oit.mint(address(this));
        return bytes4(keccak256("onERC721Received(address,address,uint256,bytes)"));
    }
}
